                     <div className="absolute -top-8 left-1/2 -translate-x-1/2 bg-gray-800 text-white text-[10px] py-1 px-2 rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap">{day.minutes} mins</div>
                  </div>
                  <span className={`text-[10px] font-bold ${isSameDay(day.fullDate, viewDate) ? 'text-coquette-accent' : 'text-gray-400'}`}>{day.label}</span>
                </div>
              ))}
            </div>
          </motion.div>

          <button onClick={() => setIsModalOpen(true)} className="w-full py-4 rounded-[20px] bg-white border border-coquette-accent text-coquette-accent font-bold font-coquette-body flex items-center justify-center gap-2 hover:bg-rose-50 transition-all"><Plus className="w-5 h-5" /> Manual Entry</button>
        </div>

        {/* RIGHT COLUMN - Main Content and Chronicle */}
        <div className="lg:col-span-8 flex flex-col gap-6 h-full overflow-hidden">
          {/* Orbit Stats Card */}
          <motion.div variants={itemVariants} className="bg-white border border-coquette-border rounded-[40px] p-8 shadow-sm relative overflow-hidden flex-shrink-0">
             <div className="flex flex-col md:flex-row justify-between items-center gap-8">
                <div>
                  <h2 className="text-2xl font-bold font-coquette-header text-coquette-text mb-1">{isSameDay(viewDate, new Date()) ? "Today's Orbit" : format(viewDate, 'MMMM do')}</h2>
                  <p className="text-xs text-coquette-subtext font-bold uppercase tracking-widest flex items-center gap-2"><Clock className="w-3 h-3" /> Virtual Day Reset 6:00 AM</p>
                </div>
                <div className="flex gap-6 lg:gap-10">
                  <OrbitRing value={stats.OUTPUT} target={30} color="#f4acb7" label="Output" icon={<Mic className="w-5 h-5 text-rose-400" />} />
                  <OrbitRing value={stats.LOGIC} target={45} color="#a5b4fc" label="Logic" icon={<Database className="w-5 h-5 text-indigo-400" />} />
                  <OrbitRing value={stats.IMMERSION} target={60} color="#ccd5ae" label="Immersion" icon={<Tv className="w-5 h-5 text-emerald-400" />} />
                </div>
             </div>
          </motion.div>

          {/* Chronicle Card - Independent Scrolling List */}
          <motion.div variants={itemVariants} className="flex-1 flex flex-col bg-[#fffcfc] border border-coquette-border rounded-[30px] shadow-sm overflow-hidden">
            <div className="p-6 border-b border-coquette-border flex items-center justify-between bg-white sticky top-0 z-10">
               <h2 className="text-xl font-bold font-coquette-header text-coquette-text flex items-center gap-2"><Clock className="w-5 h-5 text-coquette-gold" /> The Chronicle</h2>
               {todaysLogs.length > 0 && <span className="text-[10px] font-bold uppercase tracking-widest text-coquette-accent bg-rose-50 px-3 py-1 rounded-full">{todaysLogs.length} Sessions</span>}
            </div>

            <div className="flex-1 overflow-y-auto p-8 relative custom-scrollbar">
              {todaysLogs.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-40 space-y-4">
                  <div className="w-20 h-20 rounded-full border-2 border-dashed border-coquette-accent flex items-center justify-center"><Sparkles className="text-coquette-accent animate-pulse" /></div>
                  <p className="text-lg font-coquette-header text-coquette-text italic">"The blank page is a garden waiting to be planted."</p>
                </div>
              ) : (
                <div className="space-y-10 relative pb-4">
                  <div className="absolute left-[23px] top-4 bottom-4 w-0.5 bg-rose-100" />
                  {todaysLogs.map((log, index) => (
                    <motion.div key={log.id} initial={{ x: -10, opacity: 0 }} animate={{ x: 0, opacity: 1 }} transition={{ delay: index * 0.05 }} className="flex gap-6 relative">
                      <div className={`relative z-10 w-12 h-12 rounded-full flex items-center justify-center shadow-sm border-2 border-white ${log.category === 'OUTPUT' ? 'bg-rose-50 text-rose-400' : log.category === 'IMMERSION' ? 'bg-emerald-50 text-emerald-400' : 'bg-indigo-50 text-indigo-400'}`}>{CATEGORY_ICONS[log.category]}</div>
                      <div className="flex-1">
                        <div className="flex items-center justify-between mb-0.5"><span className="text-[10px] font-bold text-coquette-subtext uppercase tracking-widest">{format(new Date(log.timestamp), 'h:mm a')}</span><span className="text-[9px] px-2 py-0.5 rounded-full bg-gray-50 border border-gray-100 text-gray-400 font-bold">{log.category}</span></div>
                        <h3 className="text-base font-bold font-coquette-header text-coquette-text">Spent {log.durationMinutes}m on {log.category.toLowerCase()}.</h3>
                        <p className="text-xs text-gray-500 font-coquette-body italic mt-1 leading-relaxed">{log.summary}</p>
                      </div>
                    </motion.div>
                  ))}
                </div>
              )}
            </div>
          </motion.div>
        </div>
      </div>

      {/* MANUAL ENTRY MODAL */}
      <AnimatePresence>
        {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={() => setIsModalOpen(false)} className="absolute inset-0 bg-rose-900/10 backdrop-blur-sm" />
            <motion.div initial={{ scale: 0.9, opacity: 0, y: 20 }} animate={{ scale: 1, opacity: 1, y: 0 }} exit={{ scale: 0.9, opacity: 0, y: 20 }} className="relative w-full max-w-md bg-white rounded-[40px] shadow-2xl overflow-hidden border border-coquette-border">
              <div className="p-8 border-b border-rose-50 bg-rose-50/20 flex justify-between items-center">
                 <div className="flex items-center gap-3"><div className="p-3 bg-white rounded-2xl shadow-sm text-coquette-accent"><Plus className="w-5 h-5" /></div><h2 className="text-2xl font-bold font-coquette-header text-coquette-text">Scribe's Entry</h2></div>
                 <button onClick={() => setIsModalOpen(false)} className="text-gray-300 hover:text-gray-500"><X className="w-6 h-6" /></button>
              </div>
              <form onSubmit={handleSaveManualLog} className="p-8 space-y-6">
                 <div className="space-y-2"><label className="text-xs font-bold uppercase tracking-widest text-coquette-subtext">Session Category</label><div className="grid grid-cols-3 gap-2">{(['ANKI', 'IMMERSION', 'GRAMMAR'] as ActivityCategory[]).map(cat => (<button key={cat} type="button" onClick={() => setNewCategory(cat)} className={`py-2 rounded-xl text-[10px] font-bold transition-all border ${newCategory === cat ? 'bg-coquette-accent border-coquette-accent text-white' : 'bg-gray-50 text-gray-400 border-transparent hover:bg-rose-50'}`}>{cat}</button>))}</div></div>
                 <div className="space-y-2"><label className="text-xs font-bold uppercase tracking-widest text-coquette-subtext">Duration (Minutes)</label><input type="number" required value={newDuration} onChange={e => setNewDuration(e.target.value)} className="w-full p-4 rounded-2xl border border-gray-100 bg-gray-50 focus:bg-white focus:ring-2 focus:ring-rose-100 outline-none font-bold text-coquette-text transition-all" /></div>
                 <div className="space-y-2"><label className="text-xs font-bold uppercase tracking-widest text-coquette-subtext">Summary / Note</label><textarea value={newSummary} onChange={e => setNewSummary(e.target.value)} placeholder="e.g. Core 6k Review" className="w-full p-4 rounded-2xl border border-gray-100 bg-gray-50 focus:bg-white focus:ring-2 focus:ring-rose-100 outline-none resize-none h-24 text-sm font-coquette-body italic transition-all" /></div>
                 <button type="submit" className="w-full py-4 rounded-[20px] bg-coquette-text text-white font-bold font-coquette-header shadow-lg hover:shadow-xl transition-all flex items-center justify-center gap-2"><Check className="w-4 h-4" /> Save Record</button>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </motion.div>
  );
};

export default ActivityLogTab;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronDown, ChevronRight, FileText, Check, Database, Eye, CheckSquare, Square, PenTool, Book, Sparkles, Save, Play, Timer as TimerIcon } from 'lucide-react';
import { useProgressStore } from '../store/progressStore';
import { containerVariants, itemVariants } from '../constants';
import { ExamMode } from '../types';
import SimulationModal from './SimulationModal';
import GrammarListModal from './GrammarListModal';
import { ParsedGrammarPoint } from '../utils/grammarParser';

// --- Types & Data ---
type ModuleId = 'genki1' | 'genki2' | 'quartet1' | 'quartet2';

interface GrammarModule {
  id: ModuleId;
  title: string;
  startChapter: number;
  endChapter: number;
}

const SYLLABUS: GrammarModule[] = [
  { id: 'genki1', title: 'Genki I (N5)', startChapter: 1, endChapter: 12 },
  { id: 'genki2', title: 'Genki II (N4)', startChapter: 13, endChapter: 23 },
  { id: 'quartet1', title: 'Quartet I (N3)', startChapter: 1, endChapter: 6 },
  { id: 'quartet2', title: 'Quartet II (N2)', startChapter: 7, endChapter: 12 },
];

const SyntaxArchive: React.FC = () => {
  const { 
    masteredChapters, 
    toggleChapter, 
    setModuleChapters,
    grammarContext, 
    setGrammarContext,
    grammarDatabase,
    importGrammar,
    addActivityLog
  } = useProgressStore();

  const [expandedModules, setExpandedModules] = useState<Record<string, boolean>>({
    'genki2': true,
    'quartet1': true
  });

  // Modal State
  const [modalData, setModalData] = useState<{ isOpen: boolean; title: string; points: ParsedGrammarPoint[] }>({
    isOpen: false,
    title: '',
    points: []
  });

  const [localContext, setLocalContext] = useState(grammarContext);
  const [isSaved, setIsSaved] = useState(false);
  const [importCount, setImportCount] = useState(0);
  const [examMode, setExamMode] = useState<ExamMode>('GRAMMAR');
  const [isSimulationOpen, setIsSimulationOpen] = useState(false);

  // --- PERSISTENT GRAMMAR TIMER STATE ---
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [displaySeconds, setDisplaySeconds] = useState(0);

  useEffect(() => {
    setLocalContext(grammarContext);
  }, [grammarContext]);

  // Load state and run refresh loop
  useEffect(() => {
    const updateTimerDisplay = () => {
      const startTime = localStorage.getItem('grammar_session_start');
      if (startTime) {
        setIsTimerRunning(true);
        const duration = Math.floor((Date.now() - Number(startTime)) / 1000);
        setDisplaySeconds(Math.max(0, duration));
      } else {
        setIsTimerRunning(false);
        setDisplaySeconds(0);
      }
    };

    updateTimerDisplay();
    const interval = setInterval(updateTimerDisplay, 1000);
    return () => clearInterval(interval);
  }, []);

  // --- LOGIC ---
  const unlockedChapters = Object.keys(grammarDatabase).filter(key => 
    grammarDatabase[key] && grammarDatabase[key].length > 0
  );
  const unlockedCount = unlockedChapters.length;
  const selectedCount = masteredChapters.length;
  const totalChapters = 35; 
  const progressPercent = Math.min(100, (unlockedCount / totalChapters) * 100);

  const getRankTitle = () => {
    if (unlockedCount < 12) return 'Novice Scribe';
    if (unlockedCount < 23) return 'Apprentice';
    if (unlockedCount < 29) return 'Scholar';
    return 'Grand Master';
  };

  const toggleModule = (id: string) => {
    setExpandedModules(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const handleBulkToggle = (e: React.MouseEvent, mod: GrammarModule) => {
    e.stopPropagation();
    const chapterCount = mod.endChapter - mod.startChapter + 1;
    const allIds: string[] = [];
    for (let i = 0; i < chapterCount; i++) {
      allIds.push(`${mod.id}_${mod.startChapter + i}`);
    }
    const allSelected = allIds.every(id => masteredChapters.includes(id));
    setModuleChapters(allIds, !allSelected);
  };

  const handleOpenGrammarModal = (e: React.MouseEvent, title: string, uniqueId: string) => {
    e.stopPropagation();
    const points = grammarDatabase[uniqueId] || [];
    setModalData({ isOpen: true, title, points });
  };

  const handleSaveContext = () => {
    const count = importGrammar(localContext);
    setImportCount(count);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const handleSimulate = () => {
    if (selectedCount === 0) return;
    setIsSimulationOpen(true);
  };

  const toggleTimer = () => {
    if (isTimerRunning) {
      // Stop
      const startTime = Number(localStorage.getItem('grammar_session_start'));
      const sessionSeconds = Math.floor((Date.now() - startTime) / 1000);

      if (sessionSeconds >= 60) {
        addActivityLog({
          timestamp: Date.now(),
          category: 'GRAMMAR',
          durationMinutes: Math.floor(sessionSeconds / 60),
          summary: 'Grammar Study Session'
        });
      }

      const total = Number(localStorage.getItem('grammar_total_time') || 0);
      localStorage.setItem('grammar_total_time', (total + sessionSeconds).toString());
      localStorage.removeItem('grammar_session_start');
      window.dispatchEvent(new Event('storage-update'));
      setIsTimerRunning(false);
      setDisplaySeconds(0);
    } else {
      // Start
      localStorage.setItem('grammar_session_start', Date.now().toString());
      setIsTimerRunning(true);
      window.dispatchEvent(new Event('storage-update'));
    }
  };

  const formatTime = (secs: number) => {
    const mins = Math.floor(secs / 60);
    const s = secs % 60;
    return `${mins.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  return (
    <motion.div 
      className="p-6 lg:p-10 w-full max-w-[1600px] mx-auto h-full flex flex-col"
      variants={containerVariants}
      initial="hidden"
      animate="visible"
    >
      {/* Header: Proficiency Gauge */}
      <motion.div variants={itemVariants} className="mb-8 p-6 relative overflow-visible transition-all duration-300 bg-white border border-coquette-border rounded-[30px] shadow-sm">
         <div className="flex justify-between items-end mb-4 relative z-20">
            <div>
               <h1 className="text-3xl font-bold tracking-widest font-coquette-header text-coquette-text">
                 GRAMMAR NOTES
               </h1>
               <div className="flex items-center gap-2 font-mono text-sm mt-1 text-coquette-subtext">
                 <span>COLLECTION: {unlockedCount}/{totalChapters}</span>
                 <span className="opacity-50">|</span>
                 <span className="font-bold">{getRankTitle()}</span>
               </div>
            </div>

            {/* Redesigned Grammar Study Timer Widget */}
            <div 
              className={`
                flex items-center gap-3 p-1 rounded-full transition-all duration-500
                ${isTimerRunning ? 'bg-rose-50 border border-rose-100 shadow-inner' : 'bg-gray-50 border border-gray-100'}
              `}
            >
              {isTimerRunning && (
                <div className="pl-4 flex flex-col items-start leading-none pr-1">
                  <span className="text-[9px] font-black uppercase tracking-[0.2em] text-rose-400 mb-0.5">Focusing</span>
                  <span className="font-mono text-xl font-black text-rose-500 tabular-nums tracking-tighter">
                    {formatTime(displaySeconds)}
                  </span>
                </div>
              )}

              <button
                onClick={toggleTimer}
                className={`
                  flex items-center justify-center gap-2 px-6 py-2.5 rounded-full font-black text-xs uppercase tracking-widest transition-all duration-300 shadow-sm
                  ${isTimerRunning
                    ? 'bg-rose-500 text-white hover:bg-rose-600 active:scale-95'
                    : 'bg-coquette-accent text-white hover:bg-[#ff9eb0] active:scale-95'}
                `}
              >
                {isTimerRunning ? (
                  <>
                    <Square className="w-4 h-4 fill-current" />
                    Stop
                  </>
                ) : (
                  <>
                    <Play className="w-4 h-4 fill-current ml-0.5" />
                    Start
                  </>
                )}
              </button>
            </div>
         </div>
         {/* Progress Bar */}
         <div className="w-full h-3 rounded-full overflow-hidden relative z-10 bg-gray-100">
            <motion.div 
              className="h-full bg-gradient-to-r from-coquette-accent to-coquette-gold"
              initial={{ width: 0 }}
              animate={{ width: `${progressPercent}%` }}
              transition={{ duration: 1, ease: 'easeOut' }}
            />
         </div>
      </motion.div>

      {/* Grid Layout */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 flex-1 overflow-hidden h-full">

        {/* Left Column: Syllabus Tree */}
        <motion.div 
          variants={itemVariants} 
          className="lg:col-span-7 flex flex-col overflow-hidden h-full border bg-white border-coquette-border rounded-[25px] shadow-sm"
        >
          <div className="p-4 border-b font-bold tracking-wider text-sm flex items-center gap-2 bg-[#fffbfb] border-coquette-border text-coquette-text font-coquette-body">
             <Book className="w-4 h-4 text-coquette-gold" />
             Table of Contents
          </div>

          <div className="flex-1 overflow-y-auto p-4 scrollbar-thin scrollbar-thumb-coquette-accent/50">
            <div className="space-y-4">
               {SYLLABUS.map((mod) => {
                 const isExpanded = expandedModules[mod.id];
                 const chapterCount = mod.endChapter - mod.startChapter + 1;

                 const unlockedInMod = unlockedChapters.filter(c => c.startsWith(mod.id)).length;
                 const progressInModPercent = chapterCount > 0 ? (unlockedInMod / chapterCount) * 100 : 0;
                 const selectedInMod = masteredChapters.filter(c => c.startsWith(mod.id)).length;
                 const isFullySelected = selectedInMod === chapterCount && chapterCount > 0;

                 return (
                   <div key={mod.id} className="relative">
                     {/* Module Header */}
                     <div 
                       className={`w-full flex flex-col rounded-xl border transition-all duration-300 relative z-10 overflow-hidden
                         ${isExpanded 
                           ? 'bg-coquette-bg border-coquette-gold/50 shadow-sm' 
                           : 'bg-white border-gray-200 hover:border-coquette-gold/30'}
                       `}
                     >
                        <div 
                          className="flex items-center justify-between p-4 cursor-pointer"
                          onClick={() => toggleModule(mod.id)}
                        >
                           <div className="flex items-center gap-3">
                              {isExpanded ? <ChevronDown className="w-5 h-5 text-coquette-gold" /> : <ChevronRight className="w-5 h-5 text-gray-500" />}
                              <span className={`font-bold tracking-wide font-coquette-body ${isExpanded ? 'text-coquette-text' : 'text-gray-400'}`}>
                                {mod.title}
                              </span>
                           </div>

                           <button 
                             onClick={(e) => handleBulkToggle(e, mod)}
                             className="text-gray-500 hover:text-white transition-colors p-1"
                             title={isFullySelected ? "Deselect All" : "Select All"}
                           >
                             {isFullySelected 
                               ? <CheckSquare className="w-5 h-5 text-coquette-accent" /> 
                               : <Square className="w-5 h-5" />}
                           </button>
                        </div>

                        {/* Module Progress */}
                        <div className="w-full h-1 bg-gray-200">
                            <div 
                              className="h-full transition-all duration-500 bg-coquette-sage" 
                              style={{ width: `${progressInModPercent}%` }} 
                            />
                        </div>
                     </div>

                     {/* Chapters List */}
                     <AnimatePresence>
                       {isExpanded && (
                         <motion.div 
                           initial={{ height: 0, opacity: 0 }}
                           animate={{ height: 'auto', opacity: 1 }}
                           exit={{ height: 0, opacity: 0 }}
                           className="overflow-hidden"
                         >
                           <div className="grid grid-cols-1 md:grid-cols-2 gap-3 p-4 pl-8 border-l ml-6 mt-2 border-coquette-gold/20">
                              {Array.from({ length: chapterCount }, (_, i) => {
                                 const chapterNum = mod.startChapter + i;
                                 const uniqueId = `${mod.id}_${chapterNum}`;
                                 const isSelected = masteredChapters.includes(uniqueId);
                                 const chapterPoints = grammarDatabase[uniqueId] || [];
                                 const hasData = chapterPoints.length > 0;

                                 return (
                                   <div key={uniqueId} className="flex flex-col gap-1">
                                      <div 
                                        className={`flex items-center justify-between p-2 pl-3 rounded-lg border text-sm transition-all duration-200 group
                                          ${isSelected 
                                            ? 'bg-coquette-accent/10 border-coquette-accent/30 text-coquette-text' 
                                            : 'bg-gray-50 border-gray-100 text-gray-500'}
                                        `}
                                      >
                                          <div className="flex items-center gap-2 flex-1 font-coquette-body">
                                             <span className={hasData ? "text-coquette-sage font-bold" : ""}>CH {chapterNum}</span>
                                             {hasData && (
                                               <span className="text-[9px] px-1.5 py-0.5 rounded border bg-coquette-sage/10 text-coquette-sage border-coquette-sage/20">
                                                 {chapterPoints.length} PTS
                                               </span>
                                             )}
                                          </div>

                                          <div className="flex items-center gap-1">
                                            {hasData && (
                                              <button
                                                onClick={(e) => handleOpenGrammarModal(e, `${mod.title} - Chapter ${chapterNum}`, uniqueId)}
                                                className="w-7 h-7 flex items-center justify-center rounded transition-colors text-gray-400 hover:text-coquette-text hover:text-white hover:bg-coquette-bg"
                                              >
                                                <Eye className="w-4 h-4" />
                                              </button>
                                            )}

                                            <button 
                                                onClick={() => toggleChapter(uniqueId)}
                                                className={`w-7 h-7 flex items-center justify-center rounded-md border transition-all duration-300 ml-1
                                                ${isSelected 
                                                  ? 'bg-coquette-accent border-coquette-accent text-white shadow-sm' 
                                                  : 'border-gray-300 bg-white hover:border-coquette-accent'}
                                                `}
                                            >
                                                <Check className="w-4 h-4" />
                                            </button>
                                          </div>
                                      </div>
                                   </div>
                                 );
                              })}
                           </div>
                         </motion.div>
                       )}
                     </AnimatePresence>
                   </div>
                 );
               })}
            </div>
          </div>
        </motion.div>

        {/* Right Column: Ops Deck */}
        <motion.div variants={itemVariants} className="lg:col-span-5 flex flex-col gap-4 h-full">

          {/* Data Uplink */}
          <div className="flex-1 border rounded-2xl p-5 backdrop-blur-sm flex flex-col min-h-[220px] bg-white border-coquette-border shadow-sm">
            <div className="flex items-center gap-3 mb-3 border-b pb-3 border-coquette-border text-coquette-text">
              <div className="p-2 rounded-lg bg-coquette-bg">
                <FileText className="w-5 h-5" />
              </div>
              <div>
                <h3 className="font-bold tracking-wider font-coquette-header">
                  Notes Import
                </h3>
                <p className="text-[10px] text-gray-500 font-mono">IMPORT ANKI / TEXT DATA FOR AI CONTEXT</p>
              </div>
            </div>

            <textarea 
              value={localContext}
              onChange={(e) => setLocalContext(e.target.value)}
              className="flex-1 border rounded-xl p-3 text-xs font-mono focus:outline-none focus:ring-1 resize-none mb-3 custom-scrollbar leading-relaxed bg-[#fffcfc] border-gray-200 text-coquette-text focus:border-coquette-gold focus:ring-coquette-gold placeholder:text-gray-400"
              placeholder={`Paste your grammar export here...\n\nFormat: Point [TAB] Meaning [TAB] Sentence [TAB] ... [TAB] Tag`}
