                ${isSaved 
                  ? 'bg-coquette-sage/20 text-coquette-sage border-coquette-sage/50' 
                  : 'bg-coquette-bg text-coquette-gold border border-coquette-gold/30 hover:bg-coquette-gold/10'}
              `}
            >
              {isSaved ? <Check className="w-5 h-5" /> : <Save className="w-5 h-5" />}
              {isSaved ? `SAVED: ${importCount} NODES` : 'Save to Journal'}
            </button>
          </div>

          {/* Simulation Deck */}
          <div className="border rounded-2xl p-6 flex flex-col justify-center items-center text-center relative overflow-hidden group shadow-2xl gap-4 bg-white border-coquette-border">
             {/* Background Pattern */}
             <div className="absolute inset-0 opacity-10 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-pink-200 to-transparent"></div>

             <div className="flex flex-col items-center relative z-10">
               <Sparkles className={`w-10 h-10 mb-2 transition-colors ${selectedCount > 0 ? 'text-coquette-accent' : 'text-gray-300'}`} />

               <h3 className="text-2xl font-bold mb-1 font-coquette-header text-coquette-text">
                 Practice Session
               </h3>
               <p className="text-gray-400 font-mono text-xs">
                 Review content from <span className="font-bold text-coquette-text">{selectedCount}</span> selected chapters.
               </p>
             </div>

             {/* Mode Selector */}
             <div className="w-full grid grid-cols-3 gap-1 p-1 rounded-lg border relative z-10 bg-gray-50 border-gray-200">
               {(['GRAMMAR', 'READING', 'VOCAB'] as ExamMode[]).map((mode) => (
                 <button
                   key={mode}
                   onClick={() => setExamMode(mode)}
                   className={`text-[10px] font-bold py-2 rounded transition-all duration-300 ${
                     examMode === mode 
                     ? 'bg-coquette-accent text-white shadow-sm' 
                     : 'text-gray-400 hover:text-gray-600 hover:bg-white'
                   }`}
                 >
                   {mode}
                 </button>
               ))}
             </div>

             <button
               onClick={handleSimulate}
               disabled={selectedCount === 0}
               className={`w-full py-4 rounded-lg font-black tracking-[0.2em] text-base border-2 relative overflow-hidden transition-all duration-300 transform relative z-10 font-coquette-body
                 ${selectedCount > 0 
                   ? 'bg-white border-coquette-gold text-coquette-text hover:bg-coquette-bg hover:scale-[1.02]' 
                   : 'bg-gray-100 text-gray-300 border-gray-200'}
               `}
             >
               <span className="relative z-10 flex items-center justify-center gap-3">
                 <PenTool className="w-5 h-5" />
                 BEGIN REVIEW
               </span>
             </button>
          </div>

        </motion.div>
      </div>

      {/* Modals */}
      <SimulationModal 
        isOpen={isSimulationOpen} 
        onClose={() => setIsSimulationOpen(false)}
        mode={examMode}
      />

      <GrammarListModal 
        isOpen={modalData.isOpen}
        onClose={() => setModalData(prev => ({ ...prev, isOpen: false }))}
        title={modalData.title}
        points={modalData.points}
      />
    </motion.div>
  );
};

