import { GoogleGenAI, Type } from "@google/genai";
import { QuizQuestion, ExamMode } from "../types";

// Initialize GoogleGenAI
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateQuiz = async (
  chapters: string[],
  mode: ExamMode,
  userContext: string,
  targetGrammarPoints: string[] = [],
  isJLPTMode: boolean = true
): Promise<QuizQuestion[]> => {
  if (chapters.length === 0) {
    throw new Error("No chapters selected.");
  }

  const isAdvanced = chapters.some(c => c.includes('quartet'));
  const level = isAdvanced ? 'JLPT N3/N2' : 'JLPT N5/N4';

  let specificGrammarClause = '';
  if (targetGrammarPoints.length > 0) {
    specificGrammarClause = `
      STRICT CONSTRAINT: You must ONLY test the following specific grammar sub-points: 
      [${targetGrammarPoints.join(', ')}]
    `;
  } else {
    specificGrammarClause = `Focus on grammar found in textbook chapters: ${chapters.join(', ')}`;
  }

  let styleInstruction = '';
  if (isJLPTMode) {
    styleInstruction = `
      MODE: JLPT EXAM SIMULATION
      - Generate questions strictly adhering to JLPT format.
      - Use standard Multiple Choice (4 options).
      - Include "Star/Sorting" (sentence building) or "Fill-in-the-blank" patterns.
      - Focus on structure, particle accuracy, and pattern recognition.
    `;
  } else {
    styleInstruction = `
      MODE: DEEP UNDERSTANDING / ACTIVE PRODUCTION
      - Generate diverse, high-efficiency questions to test deep comprehension.
      - Use translation tasks (English to Japanese), error correction (find the mistake in a sentence), and complex sentence construction.
      - DO NOT use simple multiple choice if possible (though the data structure requires 4 options, make the "question" a challenge that requires thinking beyond just picking A, B, C, or D).
      - Focus on nuance and situational usage.
    `;
  }

  let modeInstruction = '';
  switch (mode) {
    case 'GRAMMAR':
      modeInstruction = `- Focus on conjugations and specific grammar structures. ${specificGrammarClause}`;
      break;
    case 'READING':
      modeInstruction = `
        - Generate a short Japanese reading passage (150-200 characters) suited for ${level}.
        - The "question" field MUST start with the Passage, followed by "\\n\\n", then the Question.
      `;
      break;
    case 'VOCAB':
      modeInstruction = `- Focus on Kanji readings, contextual synonyms, and usage.`;
      break;
  }

  const prompt = `
    You are a professional JLPT Exam Specialist and Language Coach.

    TASK: Generate 5 unique questions for a student at the ${level} level.

    ${styleInstruction}
    ${modeInstruction}

    STUDENT CONTEXT (Notes for reference): "${userContext.slice(0, 2000)}"

    OUTPUT REQUIREMENT: Return strictly JSON Array of 5 items.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctIndex: { type: Type.INTEGER },
              explanation: { type: Type.STRING },
              topic: { type: Type.STRING }
            },
            required: ['question', 'options', 'correctIndex', 'explanation', 'topic']
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as QuizQuestion[];
    }
    throw new Error("Empty response");
  } catch (error) {
    console.error("Exam Generation Error:", error);
    return [
      {
        question: "Connection error during drill generation. Which is the topic marker?",
        options: ["は", "を", "に", "へ"],
        correctIndex: 0,
        explanation: "Fallback question: 'Wa' marks the topic.",
        topic: "Particles"
      }
    ];
  }
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, AlertTriangle, RefreshCw, FileText, CheckCircle, ChevronRight, Lightbulb, Sparkles, BookHeart, GraduationCap, Zap } from 'lucide-react';
